import Nav from "./Nev";

const STYLES = `
  @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,600;0,700;1,400;1,700&family=Outfit:wght@300;400;500;600;700&display=swap');
  :root {
    --bg:#f4f1eb; --bg2:#ede8de; --surface:#ffffff; --card:#faf8f4;
    --sage:#3d6b4f; --sage-d:#2a4e39; --sage-l:#5a9470;
    --sage-xs:rgba(61,107,79,0.09); --gold:#b8922a; --gold-l:#d4ac48;
    --border:rgba(61,107,79,0.13); --text:#1c2b22; --text2:#3a4a3f;
    --muted:#7a907f; --dim:#aab8ac; --shadow:0 4px 24px rgba(30,50,35,0.08);
    --shadow-lg:0 16px 60px rgba(30,50,35,0.14); --radius:20px;
  }
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
  body{font-family:'Outfit',sans-serif;background:var(--bg);color:var(--text);}
  ::-webkit-scrollbar{width:5px;}
  ::-webkit-scrollbar-thumb{background:var(--sage);border-radius:10px;}
  @keyframes fadeUp{from{opacity:0;transform:translateY(28px)}to{opacity:1;transform:none}}
  @keyframes orbDrift{0%,100%{transform:translate(0,0)}40%{transform:translate(40px,-30px)}70%{transform:translate(-20px,20px)}}
  @keyframes spin{to{transform:rotate(360deg)}}
  @keyframes toastIn{from{opacity:0;transform:translateX(-50%) translateY(20px)}to{opacity:1;transform:translateX(-50%) translateY(0)}}
  @keyframes popIn{0%{transform:scale(0.92);opacity:0}100%{transform:scale(1);opacity:1}}

  /* HERO */
  .pr-hero{background:linear-gradient(160deg,#1e3a28 0%,#2a5a3c 55%,#1a4030 100%);padding:100px 64px 56px;position:relative;overflow:hidden;}
  .pr-orb{position:absolute;border-radius:50%;pointer-events:none;filter:blur(80px);}
  .pr-orb-1{width:600px;height:600px;background:radial-gradient(circle,rgba(90,148,112,0.25),transparent 65%);top:-220px;right:-120px;animation:orbDrift 10s ease-in-out infinite;}
  .pr-orb-2{width:400px;height:400px;background:radial-gradient(circle,rgba(184,146,42,0.14),transparent 65%);bottom:-100px;left:-60px;animation:orbDrift 13s ease-in-out infinite reverse;}
  .pr-hero-inner{position:relative;z-index:2;max-width:1320px;margin:0 auto;}
  .pr-hero-chip{display:inline-flex;align-items:center;gap:8px;background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.18);border-radius:50px;padding:7px 20px;font-size:0.7rem;font-weight:700;letter-spacing:0.16em;text-transform:uppercase;color:rgba(255,255,255,0.75);margin-bottom:20px;animation:fadeUp 0.5s ease both;backdrop-filter:blur(8px);}
  .pr-hero-dot{width:7px;height:7px;background:#5a9470;border-radius:50%;}
  .pr-hero-title{font-family:'Cormorant Garamond',serif;font-size:clamp(2.8rem,5.5vw,5rem);font-weight:700;line-height:0.92;color:#fff;animation:fadeUp 0.5s 0.1s ease both;margin-bottom:14px;}
  .pr-hero-title em{font-style:italic;color:var(--gold-l);}
  .pr-hero-sub{font-size:0.95rem;color:rgba(255,255,255,0.45);max-width:500px;line-height:1.8;animation:fadeUp 0.5s 0.2s ease both;}

  /* WRAP */
  .pr-wrap{max-width:1320px;margin:0 auto;padding:0 64px;}
  .pr-section{padding:60px 0 80px;background:var(--bg);}

  /* label-tag */
  .label-tag{font-size:0.7rem;font-weight:700;letter-spacing:0.2em;text-transform:uppercase;color:var(--sage);display:flex;align-items:center;gap:8px;margin-bottom:8px;}
  .label-tag::before{content:'';width:24px;height:2px;background:var(--sage);border-radius:2px;}

  /* SECTION HEADER */
  .pr-sec-header{text-align:center;margin-bottom:44px;}
  .pr-sec-title{font-family:'Cormorant Garamond',serif;font-size:clamp(2rem,3.5vw,2.8rem);font-weight:700;color:var(--text);margin-bottom:10px;line-height:1.1;}
  .pr-sec-sub{font-size:0.9rem;color:var(--muted);max-width:480px;margin:0 auto;line-height:1.75;}

  /* PRODUCT GRID */
  .pr-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:22px;}

  /* PRODUCT CARD */
  .pr-card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);overflow:hidden;transition:all 0.45s cubic-bezier(.34,1.56,.64,1);position:relative;animation:popIn 0.4s ease both;}
  .pr-card:hover{transform:translateY(-10px);box-shadow:var(--shadow-lg);border-color:rgba(61,107,79,0.3);}
  .pr-img-wrap{position:relative;overflow:hidden;height:220px;background:var(--card);}
  .pr-img{width:100%;height:100%;object-fit:cover;transition:transform 0.55s ease;}
  .pr-card:hover .pr-img{transform:scale(1.07);}
  .pr-img-placeholder{width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:4rem;background:linear-gradient(135deg,rgba(61,107,79,0.07),rgba(184,146,42,0.1));}
  .pr-badge{position:absolute;top:12px;left:12px;padding:4px 11px;border-radius:50px;font-size:0.65rem;font-weight:700;color:#fff;text-transform:uppercase;letter-spacing:0.08em;backdrop-filter:blur(6px);}
  .pr-badge-new{background:var(--sage);}
  .pr-badge-popular{background:#7c5cfc;}

  .pr-body{padding:18px 20px 20px;}
  .pr-pname{font-family:'Cormorant Garamond',serif;font-size:1.2rem;font-weight:700;color:var(--text);margin-bottom:4px;line-height:1.2;}
  .pr-desc{font-size:0.78rem;color:var(--muted);line-height:1.65;margin-bottom:14px;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;}
  .pr-footer{display:flex;align-items:center;justify-content:space-between;gap:8px;}
  .pr-price{font-family:'Cormorant Garamond',serif;font-size:1.35rem;font-weight:700;color:var(--sage-d);}
  .pr-price span{font-family:'Outfit',sans-serif;font-size:0.72rem;color:var(--muted);font-weight:400;}

  /* ADD TO CART BUTTON */
  .pr-atc-btn{padding:10px 18px;border-radius:50px;border:none;cursor:pointer;font-family:'Outfit',sans-serif;font-weight:700;font-size:0.8rem;transition:all 0.25s;white-space:nowrap;display:flex;align-items:center;gap:6px;}
  .pr-atc-btn-idle{background:var(--sage-l);color:#fff;box-shadow:0 4px 14px rgba(61,107,79,0.28);}
  .pr-atc-btn-idle:hover{background:var(--sage-d);box-shadow:0 8px 22px rgba(61,107,79,0.38);transform:translateY(-1px);}
  .pr-atc-btn-loading{background:var(--sage-xs);color:var(--sage);border:1.5px solid var(--border);cursor:not-allowed;}
  .pr-atc-btn-done{background:#3ecf8e;color:#fff;box-shadow:0 4px 14px rgba(62,207,142,0.3);}
  .pr-spinner{width:14px;height:14px;border:2px solid rgba(61,107,79,0.2);border-top:2px solid var(--sage);border-radius:50%;animation:spin 0.7s linear infinite;}

  /* EMPTY STATE */
  .pr-empty{text-align:center;padding:80px 20px;color:var(--muted);}
  .pr-empty-icon{font-size:60px;margin-bottom:16px;}
  .pr-empty-title{font-family:'Cormorant Garamond',serif;font-size:1.8rem;font-weight:700;color:var(--text);margin-bottom:8px;}

  /* LOADING */
  .pr-loading{text-align:center;padding:80px 20px;}
  .pr-big-spinner{width:48px;height:48px;border:3px solid var(--border);border-top:3px solid var(--sage);border-radius:50%;animation:spin 0.8s linear infinite;margin:0 auto 16px;}

  /* TOAST */
  .pr-toast{position:fixed;bottom:28px;left:50%;transform:translateX(-50%);padding:12px 26px;border-radius:50px;color:#fff;font-family:'Outfit',sans-serif;font-size:0.85rem;font-weight:600;box-shadow:0 8px 28px rgba(0,0,0,0.2);z-index:9999;animation:toastIn 0.3s ease both;white-space:nowrap;}
  .pr-toast-ok{background:var(--sage-d);}
  .pr-toast-err{background:#c0335a;}

  /* RESPONSIVE */
  @media(max-width:1100px){.pr-grid{grid-template-columns:repeat(2,1fr);}.pr-wrap{padding:0 36px;}.pr-hero{padding:100px 36px 50px;}}
  @media(max-width:680px){.pr-grid{grid-template-columns:1fr;}.pr-wrap{padding:0 16px;}.pr-hero{padding:90px 16px 40px;}}
`;

const getCategoryEmoji = (name = "") => {
  const n = name.toLowerCase();
  if (["dog","puppy","golden","labrador","husky","terrier","alaskan","malamute","affenpinscher","retriever","poodle","beagle"].some(k=>n.includes(k))) return "🐕";
  if (["cat","kitten","persian","maine","siamese","bengal"].some(k=>n.includes(k))) return "🐱";
  if (["bird","parrot","ringneck","cockatiel","macaw"].some(k=>n.includes(k))) return "🦜";
  if (["fish","aqua","arowana","betta","goldfish"].some(k=>n.includes(k))) return "🐠";
  if (n.includes("rabbit")) return "🐇";
  return "🐾";
};

function Product() {
  const [data,    setData]    = useState([]);
  const [loading, setLoading] = useState(true);
  const [btnState,setBtnState]= useState({}); // per-product: 'idle'|'loading'|'done'
  const [toast,   setToast]   = useState(null); // {msg, type}
  const navigate = useNavigate();

  useEffect(() => { getProducts(); }, []);

  function getProducts() {
    fetch('http://localhost/Petshop/show.php')
      .then(r => r.json())
      .then(d => { setData(Array.isArray(d) ? d : []); setLoading(false); })
      .catch(() => setLoading(false));
  }

  const showToast = (msg, type = "ok") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 2800);
  };

  // ✅ FIX: GET request use kiya — multipart issue nahi hoga
  function handleAddToCart(e, productId) {
    e.preventDefault();

    const islogin = localStorage.getItem("islogin");
    const uid     = localStorage.getItem("id");

    if (!islogin || !uid) {
      showToast("⚠️ Pehle login karein!", "err");
      setTimeout(() => navigate('/login'), 1200);
      return;
    }

    setBtnState(prev => ({ ...prev, [productId]: 'loading' }));
    localStorage.setItem("pid", productId);

    // ✅ GET request — insert.php $_REQUEST se padhta hai, GET bhi kaam karta hai
    fetch(`http://localhost/Petshop/insert.php?pid=${productId}&uid=${uid}`)
      .then(r => r.json())
      .then(data => {
        if (data.status === "added" || data.status === "updated") {
          setBtnState(prev => ({ ...prev, [productId]: 'done' }));
          showToast(`✅ ${data.status === "updated" ? "Quantity updated in" : "Added to"} cart!`, "ok");
          // 2 second baad button reset
          setTimeout(() => setBtnState(prev => ({ ...prev, [productId]: 'idle' })), 2000);
        } else {
          throw new Error(data.msg || "Unknown error");
        }
      })
      .catch(err => {
        setBtnState(prev => ({ ...prev, [productId]: 'idle' }));
        showToast("❌ Cart mein add nahi hua. Retry karein.", "err");
        console.error("Add to cart error:", err);
      });
  }

  const getBtnClass = (pid) => {
    const st = btnState[pid] || 'idle';
    if (st === 'loading') return 'pr-atc-btn pr-atc-btn-loading';
    if (st === 'done')    return 'pr-atc-btn pr-atc-btn-done';
    return 'pr-atc-btn pr-atc-btn-idle';
  };

  const getBtnContent = (pid) => {
    const st = btnState[pid] || 'idle';
    if (st === 'loading') return <><div className="pr-spinner" /> Adding...</>;
    if (st === 'done')    return <>✓ Added!</>;
    return <>🛒 Add to Cart</>;
  };

  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: STYLES }} />
      <Nav />

      {toast && (
        <div className={`pr-toast ${toast.type === 'err' ? 'pr-toast-err' : 'pr-toast-ok'}`}>
          {toast.msg}
        </div>
      )}

      {/* HERO */}
      <section className="pr-hero">
        <div className="pr-orb pr-orb-1" /><div className="pr-orb pr-orb-2" />
        <div className="pr-hero-inner">
          <div className="pr-hero-chip"><span className="pr-hero-dot" />Live Inventory</div>
          <h1 className="pr-hero-title">
            Find Your<br/><em>Perfect Pet</em>
          </h1>
          <p className="pr-hero-sub">
            Dogs, Cats, Birds, Fish — browse our curated collection of healthy, certified pets.
            Each one ready to find their forever home.
          </p>
        </div>
      </section>

      {/* PRODUCTS */}
      <section className="pr-section">
        <div className="pr-wrap">
          <div className="pr-sec-header">
            <div className="label-tag" style={{justifyContent:"center"}}>All Pets & Products</div>
            <h2 className="pr-sec-title">Available Right Now</h2>
            <p className="pr-sec-sub">Click "Add to Cart" on any pet or product. Login required to purchase.</p>
          </div>

          {loading ? (
            <div className="pr-loading">
              <div className="pr-big-spinner" />
              <p style={{color:"var(--muted)",fontSize:"0.9rem"}}>Products load ho rahe hain...</p>
            </div>
          ) : data.length === 0 ? (
            <div className="pr-empty">
              <div className="pr-empty-icon">🐾</div>
              <div className="pr-empty-title">Koi product nahi mila</div>
              <p>Database check karein ya XAMPP chalu karein.</p>
            </div>
          ) : (
            <div className="pr-grid">
              {data.map((product, idx) => (
                <div className="pr-card" key={product.id} style={{animationDelay:`${idx*0.06}s`}}>

                  {/* Image */}
                  <div className="pr-img-wrap">
                    {product.image
                      ? <img className="pr-img" src={`http://localhost/Petshop/upload/${product.image}`} alt={product.pname}
                          onError={e => { e.target.style.display="none"; e.target.nextSibling.style.display="flex"; }} />
                      : null
                    }
                    <div className="pr-img-placeholder" style={{display: product.image ? "none" : "flex"}}>
                      {getCategoryEmoji(product.pname)}
                    </div>
                    {idx < 3 && <span className="pr-badge pr-badge-new">New</span>}
                    {idx >= 3 && idx < 6 && <span className="pr-badge pr-badge-popular">Popular</span>}
                  </div>

                  {/* Body */}
                  <div className="pr-body">
                    <div className="pr-pname">{product.pname}</div>
                    <p className="pr-desc">{product.description || "Premium quality pet available for adoption."}</p>
                    <div className="pr-footer">
                      <div className="pr-price">
                        ₹{parseInt(product.price).toLocaleString("en-IN")}
                        <span>/pet</span>
                      </div>
                      <button
                        className={getBtnClass(product.id)}
                        onClick={(e) => handleAddToCart(e, product.id)}
                        disabled={btnState[product.id] === 'loading'}
                      >
                        {getBtnContent(product.id)}
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>
    </>
  );
}

export default Product;
